mapper.select:
SELECT , p.patient_name, p.patient_no, p.gender, p.age, du.real_name AS doctor_name, ti.item_name, ti.item_code, ti.item_price, tu.real_name AS treat_doctor_name FROM treatment_apply t LEFT JOIN patient p ON t.patient_id = p.patient_id LEFT JOIN sys_user du ON t.doctor_id = du.user_id LEFT JOIN treatment_item ti ON t.item_id = ti.item_id LEFT JOIN sys_user tu ON t.treat_doctor_id = tu.user_id
AND t.status = #{status} AND t.patient_id = #{patientId} AND t.doctor_id = #{doctorId} AND t.treat_doctor_id = #{treatDoctorId}
ORDER BY t.create_time DESC

mapper.update:
UPDATE treatment_apply
status = #{status}, treat_doctor_id = #{treatDoctorId}, treat_result = #{treatResult}, treat_time = #{treatTime}, clinical_info = #{clinicalInfo},
WHERE apply_id = #{applyId}
